    const totalBlock = isCustom
      ? '<div class="total-box custom"><span class="tlabel">PRECIO</span><span class="tval" style="font-size:12pt">Cotizaci&oacute;n especial &mdash; consultar</span></div>'
      : '<div class="total-box"><span class="tlabel">TOTAL ESTIMADO</span><span class="tval">' + q.total + ' <small>MXN</small></span></div>';

    const horarioRows = HORARIO.map(function(r) {
      return '<tr><td class="hday">' + r[0] + '</td><td>' + r[1] + '</td></tr>';
    }).join('');

    const html = '<!DOCTYPE html>\n'
